     5→//! VOK Main - Voce Viva Rust binary entry point
     6→//!
     7→//! Provides core VOK commands and delegates kit commands via external subcommand pattern.
     8→//! JJK commands (jjx_*) are handled entirely by the jjk crate when the feature is enabled.
     9→
    10→use clap::Parser;
    11→use std::ffi::OsString;
    12→use std::path::PathBuf;
    13→use std::process::ExitCode;
    14→
    15→#[derive(Parser)]
    16→#[command(name = "vvr")]
    17→#[command(version)]
    18→#[command(about = "Voce Viva Rust - Platform utilities for Claude Code kits")]
    19→#[command(allow_external_subcommands = true)]
    20→struct Cli {
    21→    #[command(subcommand)]
    22→    command: Option<Commands>,
    23→}
    24→
    25→#[derive(clap::Subcommand)]
    26→enum Commands {
    27→    /// Pre-commit size validation
    28→    Guard(GuardArgs),
    29→
    30→    /// Atomic commit with lock, stage, guard, and optional claude message
    31→    #[command(name = "vvx_commit")]
    32→    VvxCommit(CommitArgs),
    33→
    34→    /// Push with lock (prevents concurrent push/commit)
    35→    #[command(name = "vvx_push")]
    36→    VvxPush(PushArgs),
    37→
    38→    /// Force-break a stuck lock (use after crash)
    39→    #[command(name = "vvx_unlock")]
    40→    VvxUnlock,
    41→
    42→    /// Collect kit assets to staging directory
    43→    #[command(name = "release_collect")]
    44→    ReleaseCollect(ReleaseCollectArgs),
    45→
    46→    /// Brand staging directory with hallmark
    47→    #[command(name = "release_brand")]
    48→    ReleaseBrand(ReleaseBrandArgs),
    49→
    50→    /// Install kit assets from parcel to target repo
    51→    #[command(name = "vvx_emplace")]
    52→    VvxEmplace(EmplaceArgs),
    53→
    54→    /// Remove kit assets from target repo
    55→    #[command(name = "vvx_vacate")]
    56→    VvxVacate(VacateArgs),
    57→
    58→    /// External subcommands (delegated to kit CLIs)
    59→    #[command(external_subcommand)]
    60→    External(Vec<OsString>),
    61→}
    62→
    63→/// Arguments for guard command (wraps vvc)
    64→#[derive(clap::Args, Debug)]
    65→struct GuardArgs {
    66→    /// Size limit in bytes (default: 500000)
    67→    #[arg(long, default_value = "500000")]
    68→    limit: u64,
    69→
    70→    /// Warning threshold in bytes (default: 250000)
    71→    #[arg(long, default_value = "250000")]
    72→    warn: u64,
    73→}
    74→
    75→/// Arguments for vvx_commit command (wraps vvc)
    76→#[derive(clap::Args, Debug)]
    77→struct CommitArgs {
    78→    /// Prefix string to prepend to commit message
    79→    #[arg(long)]
    80→    prefix: Option<String>,
    81→
    82→    /// Commit message; if absent, invoke claude to generate from diff
    83→    #[arg(short, long)]
    84→    message: Option<String>,
    85→
    86→    /// Allow empty commits
    87→    #[arg(long)]
    88→    allow_empty: bool,
    89→
    90→    /// Skip 'git add -A' (respect pre-staged files)
    91→    #[arg(long)]
    92→    no_stage: bool,
    93→}
    94→
    95→/// Arguments for vvx_push command
    96→#[derive(clap::Args, Debug)]
    97→struct PushArgs {
    98→    /// Remote name (default: origin)
    99→    #[arg(long, default_value = "origin")]
   100→    remote: String,
   101→
   102→    /// Branch name (default: current branch)
   103→    #[arg(long)]
   104→    branch: Option<String>,
   105→
   106→    /// Force push (use with caution)
   107→    #[arg(long)]
   108→    force: bool,
   109→}
   110→
   111→/// Arguments for release_collect command
   112→#[derive(clap::Args, Debug)]
   113→struct ReleaseCollectArgs {
   114→    /// Staging directory to populate
   115→    #[arg(long)]
   116→    staging: PathBuf,
   117→
   118→    /// Source Tools/ directory
   119→    #[arg(long)]
   120→    tools_dir: PathBuf,
   121→
   122→    /// Path to vvi_install.sh
   123→    #[arg(long)]
   124→    install_script: PathBuf,
   125→
   126→    /// Comma-separated list of kit IDs (from BURC_MANAGED_KITS)
   127→    #[arg(long)]
   128→    managed_kits: String,
   129→}
   130→
   131→/// Arguments for release_brand command
   132→#[derive(clap::Args, Debug)]
   133→struct ReleaseBrandArgs {
   134→    /// Staging directory with collected assets
   135→    #[arg(long)]
   136→    staging: PathBuf,
   137→
   138→    /// Path to vovr_registry.json
   139→    #[arg(long)]
   140→    registry: PathBuf,
   141→
   142→    /// Current git commit SHA
   143→    #[arg(long)]
   144→    commit: String,
   145→
   146→    /// Comma-separated list of kit IDs (from BURC_MANAGED_KITS)
   147→    #[arg(long)]
   148→    managed_kits: String,
   149→}
   150→
   151→/// Arguments for vvx_emplace command
   152→#[derive(clap::Args, Debug)]
   153→struct EmplaceArgs {
   154→    /// Extracted parcel directory (contains vvbf_brand.json, kits/)
   155→    #[arg(long)]
   156→    parcel: PathBuf,
   157→
   158→    /// Path to target repo's burc.env file
   159→    #[arg(long)]
   160→    burc: PathBuf,
   161→}
   162→
   163→/// Arguments for vvx_vacate command
   164→#[derive(clap::Args, Debug)]
   165→struct VacateArgs {
   166→    /// Path to target repo's burc.env file
   167→    #[arg(long)]
   168→    burc: PathBuf,
   169→}
   170→
   171→#[tokio::main]
   172→async fn main() -> ExitCode {
   173→    let cli = Cli::parse();
   174→
   175→    let exit_code = match cli.command {
   176→        Some(Commands::Guard(args)) => run_guard(args),
   177→        Some(Commands::VvxCommit(args)) => run_commit(args),
   178→        Some(Commands::VvxPush(args)) => run_push(args),
   179→        Some(Commands::VvxUnlock) => run_unlock(),
   180→        Some(Commands::ReleaseCollect(args)) => run_release_collect(args),
   181→        Some(Commands::ReleaseBrand(args)) => run_release_brand(args),
   182→        Some(Commands::VvxEmplace(args)) => run_emplace(args),
   183→        Some(Commands::VvxVacate(args)) => run_vacate(args),
   184→        Some(Commands::External(args)) => dispatch_external(args),
   185→        None => {
   186→            use clap::CommandFactory;
   187→            Cli::command().print_help().ok();
   188→            0
   189→        }
   190→    };
   191→
   192→    ExitCode::from(exit_code as u8)
   193→}
   194→
   195→/// Run guard command using vvc
   196→fn run_guard(args: GuardArgs) -> i32 {
   197→    let vvc_args = vvc::vvcg_GuardArgs {
   198→        limit: args.limit,
   199→        warn: args.warn,
   200→    };
   201→    vvc::guard(&vvc_args, None)
   202→}
   203→
   204→/// Run commit command using vvc
   205→fn run_commit(args: CommitArgs) -> i32 {
   206→    let vvc_args = vvc::vvcc_CommitArgs {
   207→        prefix: args.prefix,
   208→        message: args.message,
   209→        allow_empty: args.allow_empty,
   210→        no_stage: args.no_stage,
   211→        size_limit: vvc::VVCG_SIZE_LIMIT,
   212→        warn_limit: vvc::VVCG_WARN_LIMIT,
   213→    };
   214→    vvc::commit(&vvc_args)
   215→}
   216→
   217→/// Dispatch external subcommands to appropriate kit CLIs
   218→fn dispatch_external(args: Vec<OsString>) -> i32 {
   219→    if args.is_empty() {
   220→        eprintln!("vvx: error: no subcommand provided");
   221→        return 1;
   222→    }
   223→
   224→    let cmd_name = args[0].to_string_lossy();
   225→
   226→    // Delegate to JJK if available and command matches
   227→    #[cfg(feature = "jjk")]
   228→    if jjk::jjrx_is_jjk_command(&cmd_name) {
   229→        return jjk::jjrx_dispatch(&args);
   230→    }
   231→
   232→    // Unknown external subcommand
   233→    eprintln!("vvx: error: unknown command '{}'", cmd_name);
   234→    eprintln!("Run 'vvx --help' for available commands");
   235→    1
   236→}
   237→
   238→/// Lock reference path for push operations (same as commit to prevent concurrent ops)
   239→const LOCK_REF: &str = "refs/vvg/locks/vvx";
   240→
   241→/// Force-break a stuck lock
   242→fn run_unlock() -> i32 {
   243→    use std::process::Command;
   244→
   245→    // Check if lock exists
   246→    let check = Command::new("git")
   247→        .args(["show-ref", "--verify", "--quiet", LOCK_REF])
   248→        .status();
   249→
   250→    match check {
   251→        Ok(status) if status.success() => {
   252→            // Lock exists, delete it
   253→            let delete = Command::new("git")
   254→                .args(["update-ref", "-d", LOCK_REF])
   255→                .output();
   256→
   257→            match delete {
   258→                Ok(output) if output.status.success() => {
   259→                    eprintln!("unlock: lock broken successfully");
   260→                    0
   261→                }
   262→                Ok(output) => {
   263→                    eprintln!("unlock: error: failed to delete lock: {}",
   264→                        String::from_utf8_lossy(&output.stderr));
   265→                    1
   266→                }
   267→                Err(e) => {
   268→                    eprintln!("unlock: error: {}", e);
   269→                    1
   270→                }
   271→            }
   272→        }
   273→        Ok(_) => {
   274→            // Lock doesn't exist
   275→            eprintln!("unlock: no lock held");
   276→            0
   277→        }
   278→        Err(e) => {
   279→            eprintln!("unlock: error checking lock: {}", e);
   280→            1
   281→        }
   282→    }
   283→}
   284→
   285→fn run_push(args: PushArgs) -> i32 {
   286→    use std::process::Command;
   287→
   288→    eprintln!("push: acquiring lock...");
   289→    let head_output = Command::new("git")
   290→        .args(["rev-parse", "HEAD"])
   291→        .output();
   292→
   293→    let lock_value = match head_output {
   294→        Ok(output) if output.status.success() => {
   295→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   296→        }
   297→        _ => "0000000000000000000000000000000000000000".to_string(),
   298→    };
   299→
   300→    let lock_result = Command::new("git")
   301→        .args(["update-ref", LOCK_REF, &lock_value, ""])
   302→        .output();
   303→
   304→    match lock_result {
   305→        Ok(output) if output.status.success() => {
   306→            // Lock acquired
   307→        }
   308→        _ => {
   309→            eprintln!("push: error: Another operation in progress - lock held");
   310→            return 1;
   311→        }
   312→    }
   313→
   314→    let result = run_push_workflow(&args);
   315→
   316→    let _ = Command::new("git")
   317→        .args(["update-ref", "-d", LOCK_REF])
   318→        .output();
   319→
   320→    match result {
   321→        Ok(()) => {
   322→            eprintln!("push: success");
   323→            0
   324→        }
   325→        Err(e) => {
   326→            eprintln!("push: error: {}", e);
   327→            1
   328→        }
   329→    }
   330→}
   331→
   332→fn run_push_workflow(args: &PushArgs) -> Result<(), String> {
   333→    use std::process::Command;
   334→
   335→    let branch = match &args.branch {
   336→        Some(b) => b.clone(),
   337→        None => {
   338→            let output = Command::new("git")
   339→                .args(["rev-parse", "--abbrev-ref", "HEAD"])
   340→                .output()
   341→                .map_err(|e| format!("Failed to get current branch: {}", e))?;
   342→
   343→            if !output.status.success() {
   344→                return Err("Failed to determine current branch".to_string());
   345→            }
   346→
   347→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   348→        }
   349→    };
   350→
   351→    eprintln!("push: pushing {} to {}", branch, args.remote);
   352→
   353→    let mut push_args = vec!["push", &args.remote, &branch];
   354→    if args.force {
   355→        push_args.push("--force");
   356→    }
   357→
   358→    let output = Command::new("git")
   359→        .args(&push_args)
   360→        .output()
   361→        .map_err(|e| format!("Failed to run git push: {}", e))?;
   362→
   363→    if !output.status.success() {
   364→        let stderr = String::from_utf8_lossy(&output.stderr);
   365→        return Err(format!("git push failed: {}", stderr));
   366→    }
   367→
   368→    Ok(())
   369→}
   370→
   371→/// Run release_collect command
   372→fn run_release_collect(args: ReleaseCollectArgs) -> i32 {
   373→    eprintln!("release_collect: collecting assets...");
   374→    eprintln!("  staging: {}", args.staging.display());
   375→    eprintln!("  tools_dir: {}", args.tools_dir.display());
   376→    eprintln!("  install_script: {}", args.install_script.display());
   377→
   378→    // Parse comma-separated kit list
   379→    let managed_kits: Vec<String> = args.managed_kits
   380→        .split(',')
   381→        .map(|s| s.trim().to_string())
   382→        .filter(|s| !s.is_empty())
   383→        .collect();
   384→
   385→    match vof::vofr_collect(&args.tools_dir, &args.staging, &args.install_script, &managed_kits) {
   386→        Ok(result) => {
   387→            // Output JSON for bash to parse
   388→            let mut output = serde_json::Map::new();
   389→            output.insert("total_files".to_string(), serde_json::Value::Number(result.total_files.into()));
   390→            output.insert("commands_routed".to_string(), serde_json::Value::Number(result.commands_routed.into()));
   391→
   392→            let kit_counts: serde_json::Map<String, serde_json::Value> = result.kit_counts
