     5→//! VVC Probe - Claude Code environment probe
     6→//!
     7→//! Discovers model IDs and platform information by spawning minimal claude invocations.
     8→//! See Tools/vok/vov_veiled/VOSRP-probe.adoc for specification.
     9→
    10→use tokio::process::Command;
    11→
    12→/// Probe Claude Code environment for model IDs and platform information.
    13→///
    14→/// Spawns three parallel claude invocations to discover actual model versions.
    15→/// Returns a 5-line string in "key: value" format.
    16→///
    17→/// # Returns
    18→///
    19→/// Five-line string:
    20→/// ```text
    21→/// haiku: claude-3-5-haiku-20241022
    22→/// sonnet: claude-sonnet-4-20250514
    23→/// opus: claude-opus-4-5-20251101
    24→/// host: macbook-pro.local
    25→/// platform: darwin-arm64
    26→/// ```
    27→///
    28→/// On probe failure for a tier, returns "unavailable" for that tier.
    29→pub async fn vvcp_probe() -> Result<String, String> {
    30→    // Spawn three parallel claude invocations to probe model IDs
    31→    let haiku_future = probe_model_tier("haiku");
    32→    let sonnet_future = probe_model_tier("sonnet");
    33→    let opus_future = probe_model_tier("opus");
    34→
    35→    // Wait for all three probes in parallel
    36→    let (haiku_id, sonnet_id, opus_id) = tokio::join!(haiku_future, sonnet_future, opus_future);
    37→
    38→    // Collect hostname
    39→    let hostname = get_hostname().await;
    40→
    41→    // Collect platform (OS and architecture)
    42→    let platform = get_platform().await;
    43→
    44→    // Format as 5-line string
    45→    let result = format!(
    46→        "haiku: {}\nsonnet: {}\nopus: {}\nhost: {}\nplatform: {}",
    47→        haiku_id, sonnet_id, opus_id, hostname, platform
    48→    );
    49→
    50→    Ok(result)
    51→}
    52→
    53→/// Probe a single model tier by invoking claude with minimal prompt
    54→async fn probe_model_tier(tier: &str) -> String {
    55→    let output = Command::new("claude")
    56→        .args([
    57→            "-p",
    58→            "--model",
    59→            tier,
    60→            "--system-prompt",
    61→            "Report only your exact model ID string.",
    62→            "--tools",
    63→            "",
    64→            "go",
    65→        ])
    66→        .output()
    67→        .await;
    68→
    69→    match output {
    70→        Ok(output) if output.status.success() => {
    71→            String::from_utf8_lossy(&output.stdout).trim().to_string()
    72→        }
    73→        _ => "unavailable".to_string(),
    74→    }
    75→}
    76→
    77→/// Get hostname via std::env or hostname command
    78→async fn get_hostname() -> String {
    79→    // Try environment variable first
    80→    if let Ok(hostname) = std::env::var("HOSTNAME") {
    81→        return hostname;
    82→    }
    83→
    84→    // Fall back to hostname command
    85→    let output = Command::new("hostname").output().await;
    86→
    87→    match output {
    88→        Ok(output) if output.status.success() => {
    89→            String::from_utf8_lossy(&output.stdout).trim().to_string()
    90→        }
    91→        _ => "unknown".to_string(),
    92→    }
    93→}
    94→
    95→/// Get platform information (OS and architecture)
    96→async fn get_platform() -> String {
    97→    // Spawn uname -s and uname -m in parallel
    98→    let os_future = Command::new("uname").arg("-s").output();
    99→    let arch_future = Command::new("uname").arg("-m").output();
   100→
   101→    let (os_result, arch_result) = tokio::join!(os_future, arch_future);
   102→
   103→    let os = match os_result {
   104→        Ok(output) if output.status.success() => {
   105→            String::from_utf8_lossy(&output.stdout).trim().to_lowercase()
   106→        }
   107→        _ => "unknown".into(),
   108→    };
   109→
   110→    let arch = match arch_result {
   111→        Ok(output) if output.status.success() => {
   112→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   113→        }
   114→        _ => "unknown".to_string(),
   115→    };
   116→
   117→    format!("{}-{}", os, arch)
   118→}
